@startuml
interface Vehiculo {
  - marca:string
  - modelo:string
  - velocidadMax:number
  encender():void
  apagar():void
  acelerar():void
  frenar():void
}

interface Recargable {
  - autonomia:string
  cargar(number):void
  descargar(number):void
}

class BiciElectrica {
  - pedalear():void
}

class AutoElectrico {
  manejoAutonomo():void
}

class MonopatinElectrico {
  ajustarAltura():void
  plegar():void
}

interface VehiculoRecargable {
}

Vehiculo <|-- VehiculoRecargable
Recargable <|-- VehiculoRecargable
BiciElectrica <.. VehiculoRecargable
AutoElectrico <.. VehiculoRecargable
MonopatinElectrico <.. VehiculoRecargable

@enduml
